601			Promise.all(providers.map(async (p) => ({
602				provider: p,
603				key: (await storage.providerKeys.get(p)) ?? "",
604			}))).then((results) => {
605				const map: Record<string, string> = {};
606				for (const { provider, key } of results) map[provider] = key;
607				setKeys(map);
608			});
609		}, [providers.join(",")]);
610	
611		useEffect(() => {
612			const checkOAuth = async () => {
613				const status: Record<string, boolean> = {};
614				for (const provider of providers) {
615					const oauthId = providerToOAuthId(provider);
616					if (oauthId) {
617						const creds = await loadOAuthCredentials(oauthId);
618						status[provider] = !!creds;
619					}
620				}
621				setOAuthStatus(status);
622			};
623			checkOAuth();
624		}, [providers.join(",")]);
625	
626		useEffect(() => {
627			const handler = (event: MessageEvent) => {
628				if (event.data?.type !== "keating-oauth-result") return;
629				const { success, provider: oauthProvider } = event.data;
630				if (success && oauthProvider) {
631					setOAuthStatus((prev) => ({ ...prev, [oauthProvider]: true }));
632				}
633				setOauthLoading((prev) => {
634					const next = { ...prev };
635					for (const k of Object.keys(next)) next[k] = false;
636					return next;
637				});
638			};
639			window.addEventListener("message", handler);
640			return () => window.removeEventListener("message", handler);
641		}, []);
642	
643		const save = async (provider: string, value: string) => {
644			const storage = getAppStorage();
645			if (value.trim()) {
646				await storage.providerKeys.set(provider, value.trim());
647			} else {
648				await storage.providerKeys.delete(provider);
649			}
650		};
651	
652		const handleSignIn = (provider: string) => {
653			const oauthId = providerToOAuthId(provider);
654			if (!oauthId) return;
655			setOauthLoading((prev) => ({ ...prev, [provider]: true }));
656			initiateOAuth(oauthId);
657		};
658	
659		const handleSignOut = async (provider: string) => {
660			const oauthId = providerToOAuthId(provider);
661			if (!oauthId) return;
662			await deleteOAuthCredentials(oauthId);
663			const storage = getAppStorage();
664			await storage.providerKeys.delete(provider);
665			setOAuthStatus((prev) => ({ ...prev, [provider]: false }));
666			setKeys((prev) => ({ ...prev, [provider]: "" }));
667		};
668	
669		const OAUTH_PROVIDER_LABELS: Record<string, string> = {
670			anthropic: "Anthropic",
671			"openai-codex": "OpenAI Codex",
672			google: "Google Gemini",
673		};
674	
675		return (
676			<>
677				{providers.map((provider) => {
678					const oauthId = providerToOAuthId(provider);
679					const isOAuth = !!oauthId;
680					const hasOAuth = oauthStatus[provider] === true;
681					const loading = oauthLoading[provider] === true;
682	
683					if (isOAuth) {
684						return (
685							<div key={provider} className="flex flex-col gap-1">
686								<label className="text-xs font-medium text-muted-foreground capitalize">
687									{OAUTH_PROVIDER_LABELS[provider] ?? provider}
688								</label>
689								{hasOAuth ? (
690									<div className="flex items-center justify-between gap-3 rounded-md border border-border bg-muted/30 px-3 py-2">
691										<span className="text-sm text-muted-foreground">Signed in</span>
692										<button
693											className="text-xs text-muted-foreground hover:text-foreground underline underline-offset-2"
694											onClick={() => handleSignOut(provider)}
695										>
696											Sign out
697										</button>
698									</div>
699								) : (
700									<button
701										className="inline-flex items-center justify-center rounded-md bg-primary px-3 py-2 text-sm font-medium text-primary-foreground hover:bg-primary/90 transition-colors disabled:opacity-50"
702										disabled={loading}
703										onClick={() => handleSignIn(provider)}
704									>
705										{loading ? "Waiting for sign-in…" : `Sign in with ${OAUTH_PROVIDER_LABELS[provider] ?? provider}`}
706									</button>
707								)}
708							</div>
709						);
710					}
711	
712					return (
713						<div key={provider} className="flex flex-col gap-1">
714							<label className="text-xs font-medium text-muted-foreground capitalize">{provider} API Key</label>
715							<input
716								type="password"
717								className="rounded-md border border-border bg-background px-3 py-2 text-sm"
718								placeholder={`${provider} API key`}
719								value={keys[provider] ?? ""}
720								onChange={(e) => setKeys((prev) => ({ ...prev, [provider]: e.target.value }))}
721								onBlur={(e) => save(provider, e.target.value)}
722							/>
723						</div>
724					);
725				})}
726			</>
727		);
728	}
