				lmstudio: "http://localhost:1234",
				"openai-completions": "",
				"openai-responses": "",
				"anthropic-messages": "",
				synthetic: "https://api.synthetic.new/openai/v1",
			};
			setProviderForm({ name: "", type: providerDialog.type, baseUrl: defaults[providerDialog.type] || "", apiKey: "" });
		}
