330		// Policies
331		async savePolicy(content: string, active: boolean = true): Promise<Policy> {
332			// Deactivate other policies if this one is active
333			if (active) {
334				const policies = await this.getAll<Policy>(STORES.POLICIES);
335				for (const p of policies) {
336					if (p.active) {
337						p.active = false;
338						p.updatedAt = Date.now();
339						await this.put(STORES.POLICIES, p);
340					}
341				}
342			}
343	
