361			return this.getAll<Policy>(STORES.POLICIES);
362		}
363	
364		// Feedback
365		async recordFeedback(topic: string, signal: "thumbs-up" | "thumbs-down" | "confused"): Promise<FeedbackEntry> {
366			const entry: FeedbackEntry = {
367				id: this.generateId(),
368				topic,
369				signal,
370				createdAt: Date.now(),
371			};
372			await this.put(STORES.FEEDBACK, entry);
373	
374			// Update learner state
375			const state = await this.getLearnerState();
376			state.feedbackHistory.push(entry);
377			if (!state.topicsExplored.includes(topic)) {
378				state.topicsExplored.push(topic);
379			}
380			state.lastSessionAt = Date.now();
381			state.sessionsCount = (state.sessionsCount || 0) + 1;
382			await this.saveLearnerState(state);
383	
384			return entry;
385		}
386	
387		async getFeedback(topic?: string): Promise<FeedbackEntry[]> {
388			if (topic) {
389				return this.getByTopic<FeedbackEntry>(STORES.FEEDBACK, topic);
390			}
391			return this.getAll<FeedbackEntry>(STORES.FEEDBACK);
392		}
393	
394		// Learner State
395		async getLearnerState(): Promise<LearnerState> {
396			const store = await this.getStore(STORES.LEARNER_STATE);
397			return new Promise((resolve, reject) => {
398				const request = store.get("learner-state");
399				request.onsuccess = () => {
400					resolve(
401						request.result || {
402							topicsExplored: [],
403							feedbackHistory: [],
404							strengths: [],
405							weaknesses: [],
406							sessionsCount: 0,
407							sessions: [],
408						}
409					);
410				};
411				request.onerror = () => reject(request.error);
412			});
413		}
414	
415		async saveLearnerState(state: LearnerState): Promise<void> {
