		const policies = await this.getAll<Policy>(STORES.POLICIES);
		for (const p of policies) {
			if (p.active) {
				p.active = false;
				p.updatedAt = Date.now();
				await this.put(STORES.POLICIES, p);
			}
		}
	}

	const policy: Policy = {
		id: this.generateId(),
		createdAt: Date.now(),
		updatedAt: Date.now(),
