262			label: "Keating Voice",
263			description:
264				"Speak one short learner-facing utterance through the optional Gemini 3.1 Flash Live speech layer. Use for brief questions, recaps, redirects, and encouragement only.",
265			parameters: {
266				type: "object",
267				properties: {
268					text: { type: "string", description: "The exact learner-facing sentence or short paragraph to speak." },
269					tags: {
270						type: "array",
271						items: { type: "string", enum: Array.from(VOICE_TAGS) },
272						description: "Voice tags such as question, explain, verify, redirect, encourage, pause, or recap.",
273					},
274					voice: { type: "string", description: "Optional voice name. Defaults to the configured Gemini Live voice." },
275					pace: { type: "string", description: "Optional pacing hint." },
276					affect: { type: "string", description: "Optional affect hint." },
277				},
278				required: ["text"],
279				additionalProperties: false,
280			},
281			execute: async (_toolCallId: string, params: Record<string, unknown>, signal?: AbortSignal) => {
282				const utterance = normalizeVoiceUtterance(params, settings);
