290							text: `${line}\n\nSpeech is enabled, but no Google API key is configured. Add a Google API key in Settings to play Gemini Live audio.`,
291						}],
292						details: {
293							provider: "gemini-live",
294							model: settings.model,
295							voiceName: utterance.voice,
296							utterance,
297							status: "missing-api-key",
298						},
299					};
300				}
301	
