309						content: [{
310							type: "text",
311							text: `${line}\n\nVoice layer failed for ${settings.model}: ${message}\nThe main chat response can continue without speech audio.`,
312						}],
313						details: {
314							provider: "gemini-live",
315							model: settings.model,
316							voiceName: utterance.voice,
317							utterance,
318							status: "speech-error",
319							error: message,
320						},
321					};
322				}
