327					}],
328					details: {
329						provider: "gemini-live",
330						model: settings.model,
331						voiceName: utterance.voice,
332						utterance,
333						transcript: result.transcript,
334						audioChunks: result.audioChunks,
335						playedChunks: result.playedChunks,
336					},
337				};
338			},
339		} as unknown as AgentTool;
340	}
