import {
	getAudioContext,
	type SpeechProvider,
	type SpeechSynthesisRequest,
	type SpeechSynthesisResult,
} from "../speech";

const REALTIME_MODELS = [
	{ value: "gpt-realtime", label: "gpt-realtime (latest)" },
	{ value: "gpt-realtime-mini", label: "gpt-realtime-mini" },
	{ value: "gpt-4o-realtime-preview-2024-12-17", label: "gpt-4o-realtime-preview" },
	{ value: "gpt-4o-mini-realtime-preview-2024-12-17", label: "gpt-4o-mini-realtime-preview" },
];

const REALTIME_VOICES = [
	"alloy",
	"ash",
	"ballad",
	"cedar",
	"coral",
	"echo",
	"marin",
	"sage",
	"shimmer",
	"verse",
];

async function mintEphemeralKey(apiKey: string, model: string, voice: string): Promise<string> {
	const response = await fetch("https://api.openai.com/v1/realtime/sessions", {
		method: "POST",
		headers: {
			"Content-Type": "application/json",
			Authorization: `Bearer ${apiKey}`,
		},
		body: JSON.stringify({
			model,
			voice,
			modalities: ["audio", "text"],
		}),
	});
	if (!response.ok) {
		const errText = await response.text().catch(() => "");
		throw new Error(`Realtime session mint failed (${response.status}): ${errText.slice(0, 200) || response.statusText}`);
	}
	const data = (await response.json()) as { client_secret?: { value?: string } };
	const value = data.client_secret?.value;
	if (!value) throw new Error("Realtime session mint returned no client_secret.value");
	return value;
}

async function attachMicrophone(pc: RTCPeerConnection): Promise<MediaStream | null> {
	if (typeof navigator === "undefined" || !navigator.mediaDevices?.getUserMedia) return null;
	try {
		const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
		stream.getAudioTracks().forEach((track) => pc.addTrack(track, stream));
		return stream;
	} catch (err) {
		console.warn("[keating:realtime] microphone unavailable", err);
		return null;
	}
}

async function synthesize(request: SpeechSynthesisRequest): Promise<SpeechSynthesisResult> {
	const { utterance, settings, getApiKey, signal } = request;
	const apiKey = await getApiKey("openai");
	if (!apiKey) {
		throw new Error("No OpenAI API key configured. Add one in Settings → Providers & Models.");
	}

	const model = settings.model || "gpt-realtime";
	const voice = utterance.voice || "marin";

	const ephemeralKey = await mintEphemeralKey(apiKey, model, voice);

	const pc = new RTCPeerConnection();
	const audioEl = typeof document !== "undefined" ? document.createElement("audio") : null;
	if (audioEl) {
		audioEl.autoplay = true;
		audioEl.style.display = "none";
		document.body.appendChild(audioEl);
	}

	let audioChunks = 0;
	let playedChunks = 0;
	let micStream: MediaStream | null = null;
	let cleanedUp = false;

	const cleanup = () => {
		if (cleanedUp) return;
		cleanedUp = true;
		try { pc.close(); } catch {}
		micStream?.getTracks().forEach((t) => t.stop());
		if (audioEl) {
			try { audioEl.pause(); } catch {}
			audioEl.srcObject = null;
			audioEl.remove();
		}
	};

	if (signal?.aborted) {
		cleanup();
		throw new Error("OpenAI Realtime aborted before start.");
	}
	signal?.addEventListener("abort", cleanup, { once: true });

	pc.ontrack = (event) => {
		audioChunks += 1;
		if (audioEl && event.streams[0]) {
			audioEl.srcObject = event.streams[0];
			audioEl.play().then(() => { playedChunks += 1; }).catch(() => {});
		}
	};

